                  : std::dynamic_pointer_cast<
                      uhd::rfnoc::rf_control::power_reference_iface>(radio_blk);

    return rx_chan_t({radio_blk,
        extension,
        rf_core,
        power_ref,
        std::get<0>(ddc_port_def),
        block_chan,
        radio_source_chain});
}

